diff --git a/NoiseTest_Daesung/FrmMain.cs b/NoiseTest_Daesung/FrmMain.cs
index 31d5598..d0cd96c 100644
--- a/NoiseTest_Daesung/FrmMain.cs
+++ b/NoiseTest_Daesung/FrmMain.cs
@@ -1374,9 +1374,17 @@ namespace NoiseTest
                         io.Commit();
                         AppendLog($"[wStep {wStep}] OUT20 OFF - 통전 검사 릴레이 OFF");

-                        io.Do_On_Force(2); // 검사위치 이동
-                        io.Commit();
-                        wStep = 5;
+                        if (!switchAngleOk)
+                        {
+                            AppendLog($"[wStep {wStep}] 스위치 각도 NG - 이후 검사 스킵, wStep = 506으로 이동");
+                            wStep = 506;
+                        }
+                        else
+                        {
+                            io.Do_On_Force(2); // 검사위치 이동
+                            io.Commit();
+                            wStep = 5;
+                        }
                     }
                     break;

@@ -1458,10 +1466,19 @@ namespace NoiseTest
                 case 102: // 웨이트 고정 후진
                     if (io.GetInput(15) && io.GetInput(18))
                     {
-                        AppendLog($"[wStep {wStep}] 웨이트 고정 후진 센서 확인됨");
+                        AppendLog($"[wStep {wStep}] 웨이트 고정 후진 센서 확인됨 - 2초 딜레이 후 테스트 시작");
                         io.Do_Off_Force(13);
                         io.Do_Off_Force(15);
                         io.Commit();
+                        sw.Restart();
+                        wStep = 102.5;
+                    }
+                    break;
+
+                case 102.5: // 2초 딜레이 후 테스트 시작
+                    if (sw.Elapsed.TotalSeconds >= 2.0)
+                    {
+                        AppendLog($"[wStep {wStep}] 2초 딜레이 완료 - 테스트 시작으로 이동");
                         wStep = 200;
                     }
                     break;

